import { Component, Event, EventEmitter, h, Host, Prop } from '@stencil/core';
import { StandaloneResultListSelectionMode } from '../wdpr-standalone-results-list.model';

@Component({
  tag: 'wdpr-standalone-results-list-guest-card-item',
  shadow: true,
})
export class WdprStandaloneResultsListGuestCardItem {
  @Prop() value: string;
  @Prop({ reflect: true }) selected: boolean = false;
  @Prop({ reflect: true }) disabled: boolean = false;
  @Prop() mode: StandaloneResultListSelectionMode = 'single';
  @Prop() label: string;
  @Prop() description: string;
  @Prop() buttonActionText: string;
  @Prop() imageSrc: string;
  @Prop() singleSelectionActionType: 'button' | 'radio' | 'ellipses' | 'none' = 'none';
  @Prop({ attribute: 'a11y-alt' }) a11yAlt: string;
  @Prop({ attribute: 'a11y-label' }) a11yLabel: string;

  @Event() wdprSelect: EventEmitter<{ value: string; selected: boolean }>;
  @Event() wdprActionClick: EventEmitter<void>;

  private _handleSelection = (event: CustomEvent<{ selected: boolean }>) => {
    event.stopPropagation();
    if (this.disabled) return;

    this.wdprSelect.emit({ value: this.value, selected: event.detail.selected });
  };

  private _handleActionClick = (event: MouseEvent) => {
    event.stopPropagation();
    this.wdprActionClick.emit();
  };

  render() {
    return (
      <Host role="listitem" data-standalone-results-list-item>
        <wdpr-guest-card isOnSurface={false} actionPosition="trailing" onWdprSelectedChange={this._handleSelection} selected={this.selected} disabled={this.disabled}>
          <wdpr-avatar slot="media" size="medium" image-src={this.imageSrc} alt-text={this.a11yAlt} labelPosition="stacked" isInteractive={false} />

          <wdpr-card-micro-content slot="content" primaryHeadline={this.label} body={this.description} />

          {this.singleSelectionActionType !== 'none' && this.mode === 'single' && (
            <wdpr-card-link slot="link" type={this.singleSelectionActionType} onClick={this._handleActionClick}>
              {this.buttonActionText}
            </wdpr-card-link>
          )}

          {this.mode === 'multiple' && (
            <wdpr-card-link slot="link" type="checkbox" a11yLabel={this.a11yLabel} checked={this.selected} onClick={this._handleActionClick} />
          )}
        </wdpr-guest-card>
      </Host>
    );
  }
}
